      // Let's simulate the greedy choice that maximizes peaks: enforce alternation.
      // We try two target patterns:
      // P1: Up, Down, Up, Down... (Peak at 1, 3, 5, ...)
      // P2: Down, Up, Down, Up... (Peak at 2, 4, 6, ...) - Wait, this requires starting with a decrease, which is hard to enforce cost-effectively.

      // Pattern 1: Try to make 1, 3, 5, ... peaks.
      // Required: nums'[0] < nums'[1] > nums'[2] < nums'[3] > nums'[4] ...

      // We simulate this specific sequence of inequalities and calculate the minimum cost.

      // Function to calculate cost for a specific required sequence of inequalities (e.g., A < B > C < D ...)
      def calculate_cost(nums: Array[Long], n: Int, pattern: Array[Boolean]): Long = {
        // pattern[i] = true means nums'[i] > nums'[i-1] (Increasing step)
        // pattern[i] = false means nums'[i] <= nums'[i-1] (Decreasing/Equal step)

        val B = nums.toMutableList.map(_ * 1L).toMutableList // Use Longs throughout
        var total_cost: Long = 0

        // We iterate, enforcing the required relative order and minimizing the increase.
        for (i <- 1 until n) {
          val required_relation = pattern(i) // pattern is indexed from 1 to n-1

          if (required_relation) { // nums'[i] > nums'[i-1]
            // Minimum target for B[i] is B[i-1] + 1
            val required_val = B(i-1) + 1
            val cost_increase = Math.max(0, required_val - B(i)).toLong
            B.set(i, B(i) + cost_increase)
            total_cost += cost_increase
          } else { // nums'[i] <= nums'[i-1]
            // Minimum target for B[i] is B[i]. We only increase B[i-1] if needed, but B[i-1] is already set.
            // If B[i] > B[i-1], we must increase B[i-1] to B[i] (violating the pattern at i-1) or decrease B[i] (not allowed).
            // Since we only increase, if B[i] > B[i-1] currently, this pattern is impossible without modifying B[i-1] which we fixed.
            // This means the pattern itself might be impossible to satisfy by only increasing elements if a previous choice locked B[i-1] too low relative to original B[i].

            // However, since we are only calculating the cost for a FIXED pattern, we assume B[i-1] is finalized.
            // To satisfy B[i] <= B[i-1], we must have B[i] <= B[i-1] *after* applying cost increases to B[i].

            // If B[i] > B[i-1] currently, and we cannot change B[i-1], this pattern is impossible.
            if (B(i) > B(i-1)) {
              return Long.MaxValue // Pattern impossible
            }
            // If B[i] <= B[i-1], we don't need to increase B[i]. Cost increase = 0.
          }
        }

