        var peaks = 0
        for (i <- 1 until n - 1) {
          if (B(i) > B(i-1) && B(i) > B(i+1)) {
            peaks += 1
          }
        }

        // Return (Peaks, Cost)
        (peaks, total_cost)
      }

      // --- Main logic using the fixed pattern simulation ---

      // Max possible peaks is floor((N-2)/2). We search downwards from this maximum.

      // 1. Target Peak Sequence 1: Peaks at 1, 3, 5, ... (Up, Down, Up, Down...)
      // Pattern: Increase at 1, 3, 5, ...
      // Indices for pattern array (1 to N-1):
      // pattern[i] = true if i is odd.
      val pattern1 = Array.fill(n) { _ => false }
      for (i <- 1 until n) {
        pattern1(i) = (i % 2 != 0)
      }

      val (peaks1, cost1) = calculate_cost(nums, n, pattern1)

      // 2. Target Peak Sequence 2: Peaks at 2, 4, 6, ... (Down, Up, Down, Up...)
      // This requires nums'[1] <= nums'[0], nums'[2] > nums'[1].
