      val pattern2 = Array.fill(n) { _ => false }
      for (i <- 1 until n) {
        pattern2(i) = (i % 2 == 0)
      }

      val (peaks2, cost2) = calculate_cost(nums, n, pattern2)

      // The optimal solution must be one of these two maximally alternating sequences, or a slightly perturbed version.
      // Since the problem asks to MAXIMIZE peaks, the alternating sequences are the best candidates.

      var max_peaks = 0
      var min_cost = Long.MaxValue

      // Compare results from P1 and P2
      if (peaks1 > max_peaks) {
        max_peaks = peaks1
        min_cost = cost1
      } else if (peaks1 == max_peaks) {
        min_cost = Math.min(min_cost, cost1)
      }

